    source_url: "https://www.sodnapraksa.si/search.php?q=&advanceSerch=1&database[UPRS]=UPRS&trib_title[Upravno sodišče]=\"Upravno sodišče\"&dep_title[Javne finance]=\"Javne finance\"&dep_title[Upravni oddelek]=\"Upravni oddelek\"&dep_title[Varstvo ustavnih pravic]=\"Varstvo ustavnih pravic\"&meet_dateFrom=10.03.2022&meet_dateTo=29.05.2026&order=date&direction=desc&_submit=išči&rowsPerPage=20&page=265&id=2015081111465990",
